// Helper function to format any data dynamically
function formatDataTable(data, title) {
  let table = `${title}:\n`;
  table += "=".repeat(80) + "\n\n";

  data.forEach((item, index) => {
    const record = item.json;
    table += `Record ${index + 1}:\n`;

    // Dynamically add ALL columns from the data
    Object.keys(record).forEach(columnName => {
      const value = record[columnName];
      // Format the column name nicely (convert underscores to spaces, capitalize)
      const formattedColumnName = columnName
        .replace(/_/g, ' ')
        .replace(/\b\w/g, char => char.toUpperCase());

      table += `  ${formattedColumnName}: ${value || 'N/A'}\n`;
    });

    table += `\n`;
  });

  return table;
}

